import { useMemo, useState } from "react";
import { useAppStore } from "../store/appStore";

function Widget({ id, title, children, onDragStart, onDragOver, onDrop, dragging }) {
  return (
    <div
      className={`v2-card third ${dragging ? "v2-drag" : ""}`}
      draggable
      onDragStart={(e) => onDragStart(e, id)}
      onDragOver={(e) => onDragOver(e, id)}
      onDrop={(e) => onDrop(e, id)}
    >
      <div className="v2-ct">{title}</div>
      {children}
    </div>
  );
}

export default function WidgetBoard({ registry }) {
  const { state, upsertProfile } = useAppStore();
  const active = state.layoutProfiles.active;
  const profile = state.layoutProfiles.profiles[active];

  const [dragId, setDragId] = useState("");

  const order = useMemo(() => {
    const base = (profile && profile.dashboardWidgets) ? profile.dashboardWidgets : [];
    const existing = base.filter(k => registry[k]);
    const missing = Object.keys(registry).filter(k => !existing.includes(k));
    return [...existing, ...missing];
  }, [profile, registry]);

  const setOrder = (next) => {
    const nextProfile = { ...(profile || {}), dashboardWidgets: next };
    upsertProfile(active, nextProfile);
  };

  const onDragStart = (e, id) => {
    setDragId(id);
    e.dataTransfer.effectAllowed = "move";
    e.dataTransfer.setData("text/plain", id);
  };

  const onDragOver = (e) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = "move";
  };

  const onDrop = (e, overId) => {
    e.preventDefault();
    const from = e.dataTransfer.getData("text/plain") || dragId;
    if (!from || from === overId) return;
    const next = [...order];
    const a = next.indexOf(from);
    const b = next.indexOf(overId);
    if (a < 0 || b < 0) return;
    next.splice(a, 1);
    next.splice(b, 0, from);
    setOrder(next);
    setDragId("");
  };

  return (
    <div className="v2-grid">
      {order.map((id) => {
        const W = registry[id];
        return (
          <Widget
            key={id}
            id={id}
            title={W.title}
            onDragStart={onDragStart}
            onDragOver={onDragOver}
            onDrop={onDrop}
            dragging={id === dragId}
          >
            <W.Render />
          </Widget>
        );
      })}
    </div>
  );
}
