import { useAppStore } from "../store/appStore";

export default function LinkedContextBar() {
  const { state, setLinked, toast } = useAppStore();

  return (
    <div className="v2-card wide" style={{ padding: 12, boxShadow: "none" }}>
      <div className="v2-row" style={{ justifyContent: "space-between" }}>
        <div className="v2-row">
          <div className="v2-muted">Linked Views</div>
          <span className="v2-pill">Strategy: <span className="v2-mono">{state.linked.strategy || "—"}</span></span>
          <span className="v2-pill">Symbol: <span className="v2-mono">{state.linked.symbol || "—"}</span></span>
          <span className="v2-pill">Bot: <span className="v2-mono">{state.linked.bot || "—"}</span></span>
        </div>

        <div className="v2-row">
          <input
            className="v2-input"
            placeholder="Strategy"
            value={state.linked.strategy}
            onChange={(e) => setLinked({ strategy: e.target.value })}
            style={{ width: 180 }}
          />
          <input
            className="v2-input"
            placeholder="Symbol"
            value={state.linked.symbol}
            onChange={(e) => setLinked({ symbol: e.target.value.toUpperCase() })}
            style={{ width: 140 }}
          />
          <input
            className="v2-input"
            placeholder="Bot"
            value={state.linked.bot}
            onChange={(e) => setLinked({ bot: e.target.value })}
            style={{ width: 140 }}
          />
          <button className="v2-btn" onClick={() => { setLinked({ strategy:"", symbol:"", bot:"" }); toast("Linked context cleared", "ok"); }}>
            Clear
          </button>
        </div>
      </div>
    </div>
  );
}
